const item = $input.item.json;
const reason = (item.reason || '').toLowerCase();
const snippet = (item.raw_snippet || item.reason || '').toLowerCase();

const entries = [];

// --- Pain detection ---
const painKeywords = ['frustrat', 'pain', 'struggle', 'difficult', 'problem', 'issue', 'bug', 'broken', 'slow', 'expensive', 'confus', 'complex', 'lack', 'missing', 'poor', 'terrible', 'worst', 'hate', 'annoying', 'unreliable'];
if (painKeywords.some(k => snippet.includes(k))) {
  entries.push({
    user_id: item.user_id,
    dimension: 'pain',
    text: item.reason,
    source_url: item.source_url,
    source_platform: item.source_platform,
    persona: null,
    funnel_stage: item.indicator_type === 'loss' ? 'decision' : 'consideration',
    raw_snippet: item.raw_snippet
  });
}

// --- Desire detection ---
const desireKeywords = ['wish', 'want', 'need', 'hope', 'dream', 'love', 'great', 'amazing', 'perfect', 'ideal', 'looking for', 'prefer', 'excited', 'recommend', 'best'];
if (desireKeywords.some(k => snippet.includes(k))) {
  entries.push({
    user_id: item.user_id,
    dimension: 'desire',
    text: item.reason,
    source_url: item.source_url,
    source_platform: item.source_platform,
    persona: null,
    funnel_stage: item.indicator_type === 'win' ? 'decision' : 'consideration',
    raw_snippet: item.raw_snippet
  });
}

// --- Language detection (buyer phrases) ---
const languageKeywords = ['roi', 'time-to-value', 'total cost', 'enterprise-grade', 'scalab', 'integration', 'workflow', 'productivity', 'collaboration', 'self-serve', 'onboard', 'user-friendly', 'intuitive', 'out-of-the-box'];
if (languageKeywords.some(k => snippet.includes(k))) {
  entries.push({
    user_id: item.user_id,
    dimension: 'language',
    text: item.reason,
    source_url: item.source_url,
    source_platform: item.source_platform,
    persona: null,
    funnel_stage: 'consideration',
    raw_snippet: item.raw_snippet
  });
}

// --- Criteria detection ---
const criteriaKeywords = ['compared', 'versus', 'vs', 'chose', 'picked', 'decided', 'evaluated', 'criteria', 'requirement', 'must-have', 'deal-breaker', 'factor', 'reason we', 'why we', 'switched because', 'moved because'];
if (criteriaKeywords.some(k => snippet.includes(k))) {
  entries.push({
    user_id: item.user_id,
    dimension: 'criteria',
    text: item.reason,
    source_url: item.source_url,
    source_platform: item.source_platform,
    persona: null,
    funnel_stage: 'decision',
    raw_snippet: item.raw_snippet
  });
}

// If no specific dimension matched, default based on indicator type
if (entries.length === 0) {
  let defaultDim = 'language';
  let defaultStage = 'consideration';
  if (item.indicator_type === 'loss') { defaultDim = 'pain'; defaultStage = 'decision'; }
  else if (item.indicator_type === 'win') { defaultDim = 'desire'; defaultStage = 'decision'; }
  else if (item.indicator_type === 'switch') { defaultDim = 'criteria'; defaultStage = 'decision'; }

  entries.push({
    user_id: item.user_id,
    dimension: defaultDim,
    text: item.reason,
    source_url: item.source_url,
    source_platform: item.source_platform,
    persona: null,
    funnel_stage: defaultStage,
    raw_snippet: item.raw_snippet
  });
}

return entries.map(e => ({ json: e }));
